import React, { useState, useContext } from "react";
import Input from "../../shared/components/FormElements/Input";
import Button from "../../shared/components/FormElements/Button";
import { VALIDATOR_EMAIL, VALIDATOR_MINLENGTH, VALIDATOR_REQUIRE } from "../../shared/components/util/validators";
import { useForm } from "../../shared/components/hooks/form-hook";
import LoadingSpinner from '../../shared/components/UIElements/'
import { AuthContext } from "../../shared/components/context/auth-context";

import './Auth.css';
import Card from "../../shared/components/UIElements/Card";

const Auth = () => {
    const auth = useContext(AuthContext);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState(false);

    const [isLoginMode, setIsLoginMode] = useState(true);
    const [formState, inputHandler, setFormData] = useForm({
        email: {
            value: '',
            isValid: false
        },
        password: {
            value: '',
            isValid: false
        }
    }, false);

    const switchModeHandler = () => {
        if (!isLoginMode) {
            setFormData({
                ...formState.inputs,
                name: undefined
            }, 
            formState.inputs.email.isValid && formState.inputs.password.isValid);
        } else {
            setFormData({
                ...formState.inputs,
                name: {
                    value:'',
                    isValid: false
                }
            }, false);
        }

        setIsLoginMode(prevMode => !prevMode);
    };

    const authSubmitHandler = async event => {
        event.preventDefault();
        
        if (isLoginMode) {

        } else {
            try {
                setIsLoading(true);
                const response = await fetch('http://localhost:5000/api/users/signup', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                name: formState.inputs.name.value,
                email: formState.inputs.email.value,
                password: formState.inputs.password.value
            })
        });

        const responseData = await response.json();
        console.log(responseData);
            } catch (err) {
                console.log(err);
                setError(err.message || 'Something went wrong, please try again.');
            }
        }
        setIsLoading(false);
        auth.login();
    };

    return <Card className="authentication">
        <h2>Login Required</h2>
        <hr />
        <form onSubmit={authSubmitHandler}>
            {!isLoginMode && 
            <Input 
            element="input"
            id="name" 
            type="text" 
            label="Your Name" 
            validators={[VALIDATOR_REQUIRE()]}
            errorText="please enter a name."
            onInput={inputHandler}
            />}
            <Input 
            element="input" 
            id="email" 
            label="E-mail" 
            validators={[VALIDATOR_EMAIL()]}
            errorText="please enter a valid email address." 
            onInput={inputHandler}
            />
            <Input 
            element="input" 
            id="password" 
            label="Password" 
            validators={[VALIDATOR_MINLENGTH(5)]}
            errorText="please enter a valid password, at least 5 characters." 
            onInput={inputHandler}
            />
            
            <Button type="submit" disabled={!formState.isValid}>{isLoginMode ? 'LOGIN' : 'SIGNUP'}</Button>
            <Button type="button" inverse onClick={switchModeHandler}>{isLoginMode ? 'SIGNUP' : 'LOGIN'}</Button>
        </form>
    </Card>;

};

export default Auth;
